import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer } from "react-leaflet";
import "leaflet/dist/leaflet.css";

export default function Radar({
  center = [33.7490, -84.3880], // fallback: Atlanta
  zoom = 5,
  height = 260,
  className = ""
}) {
  const [frameTime, setFrameTime] = useState(null);
  const [tilesLoaded, setTilesLoaded] = useState(false);
  const [tileError, setTileError] = useState(false);
  const alive = useRef(true);

  // validate center
  const safeCenter = useMemo(() => {
    const ok = Array.isArray(center) && center.length === 2 &&
      center.every((n) => typeof n === "number" && isFinite(n));
    return ok ? center : [33.7490, -84.3880];
  }, [center]);

  // fetch latest radar time
  useEffect(() => {
    alive.current = true;
    (async () => {
      try {
        const r = await fetch("https://api.rainviewer.com/public/weather-maps.json");
        const j = await r.json();
        const latest = j?.radar?.past?.at(-1)?.time ?? j?.radar?.nowcast?.[0]?.time ?? null;
        if (alive.current && latest) setFrameTime(latest);
      } catch {
        // ignore; fallback below
      }
    })();
    return () => { alive.current = false; };
  }, []);

  const effectiveTime = useMemo(() => {
    if (frameTime) return frameTime;
    // fallback: nearest 10-min (seconds)
    return Math.floor(Date.now() / (10 * 60 * 1000)) * (10 * 60);
  }, [frameTime]);

  const radarUrl = useMemo(() =>
    `https://tilecache.rainviewer.com/v2/radar/${effectiveTime}/256/{z}/{x}/{y}/2/1_1.png`
  , [effectiveTime]);

  // soft status text
  let status = "Loading radar…";
  if (tileError) status = "Radar tiles failed to load.";
  else if (tilesLoaded === false && frameTime && typeof frameTime === "number") status = "Loading radar…";
  else if (tilesLoaded === false) status = "Loading radar…";
  // If tiles load but precip is zero where you are, the layer is transparent—so we hint:
  const showNoPrecipHint = tilesLoaded && !tileError;

  return (
    <div className={`relative w-full ${className}`} style={{ height }}>
      <MapContainer
        center={safeCenter}
        zoom={zoom}
        style={{ width: "100%", height: "100%", borderRadius: 16, overflow: "hidden" }}
        scrollWheelZoom={false}
        dragging={false}
        boxZoom={false}
        doubleClickZoom={false}
        keyboard={false}
        zoomControl={false}
        attributionControl={false}
        zoomAnimation={false}
        fadeAnimation={false}
        markerZoomAnimation={false}
        inertia={false}
        preferCanvas={true}
      >
        {/* faint basemap so it's never visually blank */}
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          opacity={0.35}
        />

        {/* radar tiles (precip + snow) */}
        <TileLayer
          url={radarUrl}
          opacity={0.9}
          eventHandlers={{
            tileload: () => setTilesLoaded(true),
            load: () => setTilesLoaded(true),
            tileerror: () => setTileError(true),
          }}
          updateWhenIdle={true}
          updateWhenZooming={false}
          keepBuffer={2}
          detectRetina={false}
        />
      </MapContainer>

      {/* overlay status / hints (non-interactive) */}
      <div
        className="pointer-events-none absolute right-2 bottom-2 text-xs text-white"
        style={{ backdropFilter: "blur(6px)", background: "rgba(0,0,0,0.35)", padding: "4px 8px", borderRadius: 8 }}
      >
        {tileError ? "Radar unavailable" : "Drag disabled • use page scroll"}
      </div>

      {/* center message while loading OR if likely transparent */}
      {(!tilesLoaded || showNoPrecipHint) && (
        <div className="pointer-events-none absolute inset-0 flex items-center justify-center">
          <div
            style={{
              padding: "6px 10px",
              borderRadius: 10,
              fontSize: 12,
              color: "white",
              backdropFilter: "blur(6px)",
              background: "rgba(0,0,0,0.35)"
            }}
          >
            {tileError
              ? "Radar tiles failed to load."
              : tilesLoaded
              ? "No precipitation detected nearby."
              : status}
          </div>
        </div>
      )}
    </div>
  );
}
